/** * Echo's Master Financial Dictionary * 100+ hospitality and restaurant financial terms * Establishes Echo as the ultimate F&B operational and financial authority * * Each entry includes: * - Comprehensive definition * - Usage context (how it's used) * - Category (metric, accounting, analysis, strategy) * - Etymology and linguistic origin * - Applications in hospitality * - Related terms and connections * - Historical context * - Confidence level (based on financial authority) */ export interface MasterFinancialTerm {
  term: string;
  definition: string;
  usage: { primary: string; secondary?: string[]; context: string };
  categories: Array<
    | "metric"
    | "accounting"
    | "analysis"
    | "strategy"
    | "pricing"
    | "operations"
    | "management"
    | "reporting"
    | "labor"
    | "inventory"
  >;
  etymology: {
    origin: string;
    originalWord?: string;
    meaning?: string;
    period?: string;
  };
  applications: { primary: string; examples?: string[]; contexts?: string[] };
  relatedTerms: string[];
  history?: { period: string; industry: string; significance: string };
  confidence: number;
  sources: string[];
  masteryLevel:
    | "fundamental"
    | "intermediate"
    | "advanced"
    | "expert"
    | "master";
}
class MasterFinancialDictionary {
  private dictionary: Map<string, MasterFinancialTerm> = new Map();
  constructor() {
    this.initializeFinancialDictionary();
  }
  private initializeFinancialDictionary(): void {
    this.loadTermsFromArray(comprehensiveFinancialTerms);
  }
  addTerm(key: string, term: MasterFinancialTerm): void {
    this.dictionary.set(key.toLowerCase(), term);
  }
  getTerm(key: string): MasterFinancialTerm | undefined {
    return this.dictionary.get(key.toLowerCase());
  }
  getAllTerms(): MasterFinancialTerm[] {
    return Array.from(this.dictionary.values());
  }
  searchTerms(query: string): MasterFinancialTerm[] {
    const lowerQuery = query.toLowerCase();
    return this.getAllTerms().filter(
      (term) =>
        term.term.toLowerCase().includes(lowerQuery) ||
        term.definition.toLowerCase().includes(lowerQuery) ||
        term.relatedTerms.some((rt) => rt.toLowerCase().includes(lowerQuery)),
    );
  }
  loadTermsFromArray(terms: Array<[string, MasterFinancialTerm]>): void {
    terms.forEach(([key, term]) => {
      this.addTerm(key, term);
    });
  }
  getTermCount(): number {
    return this.dictionary.size;
  }
}
